```
public function destroy($id)
{
    // Menghapus data pada baris t_siswa yang memiliki id parameter $id
    $status = DB::table('t_siswa')->where('id', $id)->delete();

    if ($status) {
        return redirect('/siswa')->with('success', 'Data berhasil dihapus!');
